headStyle:
body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; line-height: 1.6; max-width: 800px; margin: auto; padding: 20px; color: #333; }
        h1, h2 { color: #2c3e50; border-bottom: 2px solid #eee; padding-bottom: 8px; }
        .meta { background: #f8f9fa; padding: 15px; border-radius: 8px; margin-bottom: 20px; font-weight: 600; }
        .ingredients, .instructions, .portioning { margin-bottom: 30px; }
        ul, ol { padding-left: 20px; }
        li { margin-bottom: 10px; }
        .badge { background: #e3f2fd; color: #1976d2; padding: 2px 8px; border-radius: 12px; font-size: 0.85em; font-weight: 600; }
